import React, { useState, useEffect } from "react";
import CompleteRegister from "./CompleteRegister";

export default function VerifyOTP({ email, closeModal }) {
  const BASE_URL = "http://localhost:8086";

  const [otp, setOtp] = useState("");
  const [timer, setTimer] = useState(60);
  const [error, setError] = useState("");
  const [verified, setVerified] = useState(false);

  useEffect(() => {
    if (timer > 0) {
      const t = setTimeout(() => setTimer(timer - 1), 1000);
      return () => clearTimeout(t);
    }
  }, [timer]);

  const verifyOTP = async () => {
    setError("");

    try {
      const res = await fetch(`${BASE_URL}/user/verify-otp`, {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify({ email, otp }),
      });

      const data = await res.text();

      if (res.ok) {
        setVerified(true);
      } else {
        setError(data);
      }
    } catch {
      setError("Server error");
    }
  };

  const resendOTP = async () => {
    await fetch(`${BASE_URL}/user/send-otp`, {
      method: "POST",
      headers: {"Content-Type": "application/json"},
      body: JSON.stringify({ email }),
    });
    setTimer(60);
  };

  if (verified) {
    return <CompleteRegister email={email} closeModal={closeModal} />;
  }

  return (
    <div className="p-8 bg-white/20 rounded-xl text-white">
      <h2 className="text-xl mb-4">Verify OTP</h2>

      <input
        value={otp}
        onChange={(e) => setOtp(e.target.value)}
        placeholder="Enter OTP"
        className="w-full p-2 mb-3 text-black"
      />

      {error && <p className="text-red-300">{error}</p>}

      <button onClick={verifyOTP} className="bg-green-500 px-4 py-2">
        Verify
      </button>

      <div className="mt-3">
        {timer > 0 ? (
          <p>Resend in {timer}s</p>
        ) : (
          <button onClick={resendOTP} className="text-blue-300 underline">
            Resend OTP
          </button>
        )}
      </div>
    </div>
  );
}
